        nr2c, nr2r = r2c + dc[r2d], r2r + dr[r2d]
        wall_bump2 = (r2c, r2r) if (r2d == 0 and (r2c, r2r) in ver_walls) or (r2d == 1 and (r2c, r2r+1) in hor_walls) or (r2d == 2 and (r2c-1, r2r) in ver_walls) or (r2d == 3 and (r2c, r2r-1) in hor_walls) else None
        if wall_bump2:
