from collections import deque

def main():
    cols, rows, exit_col = map(int, input().split())
    robot1_col, robot1_row, robot1_dir, robot2_col, robot2_row, robot2_dir = input().split()
    robot1_col, robot1_row = int(robot1_col), int(robot1_row)
    robot2_col, robot2_row = int(robot2_col), int(robot2_row)

    dirs = {'N': (-1, 0), 'E': (0, 1), 'S': (1, 0), 'W': (0, -1)}
    robot1_dir = dirs[robot1_dir]
    robot2_dir = dirs[robot2_dir]

    n, *walls = map(int, input().split())
    horizontal_walls = set()
    for i in range(0, len(walls), 2):
        horizontal_walls.add((walls[i], walls[i+1]))

    n, *walls = map(int, input().split())
    vertical_walls = set()
    for i in range(0, len(walls), 2):
        vertical_walls.add((walls[i], walls[i+1]))

    def is_valid(col, row, new_col, new_row):
        if new_col < 1 or new_col > cols or new_row < 1 or new_row > rows:
            return False
        if new_col != col:
            if new_col > col and (col, row) in vertical_walls:
                return False
            if new_col < col and (new_col, row) in vertical_walls:
                return False
        if new_row != row:
            if new_row > row and (col, row) in horizontal_walls:
                return False
            if new_row < row and (new_col, new_row) in horizontal_walls:
                return False
        return True

    queue = deque([(robot1_col, robot1_row, robot1_dir, robot2_col, robot2_row, robot2_dir, 0, 0)])
    visited = set((robot1_col, robot1_row, robot2_col, robot2_row))
    min_steps = float('inf')
    min_bumps = float('inf')

    while queue:
        r1c, r1r, r1d, r2c, r2r, r2d, steps, bumps = queue.popleft()

        if (r1c, r1r) == (exit_col, 1) or (r2c, r2r) == (exit_col, 1):
            if steps < min_steps or (steps == min_steps and bumps < min_bumps):
                min_steps = steps
                min_bumps = bumps
            continue

        new_r1c, new_r1r = r1c + r1d[0], r1r + r1d[1]
        new_r2c, new_r2r = r2c + r2d[0], r2r + r2d[1]

        new_bumps = bumps
        if not is_valid(r1c, r1r, new_r1c, new_r1r):
            new_r1c, new_r1r = r1c, r1r
            new_bumps += 1
        if not is_valid(r2c, r2r, new_r2c, new_r2r):
            new_r2c, new_r2r = r2c, r2r
            new_bumps += 1

        if (new_r1c, new_r1r, new_r2c, new_r2r) not in visited and (new_r1c, new_r1r) != (new_r2c, new_r2r):
            queue.append((new_r1c, new_r1r, r1d, new_r2c, new_r2r, r2d, steps + 1, new_bumps))
            visited.add((new_r1c, new_r1r, new_r2c, new_r2r))

        new_r1d = (-r1d[1], r1d[0])
        new_r2d = (-r2d[1], r2d[0])
        if (r1c, r1r, new_r1d, r2c, r2r, new_r2d) not in visited:
            queue.appendleft((r1c, r1r, new_r1d, r2c, r2r, new_r2d, steps, bumps))
            visited.add((r1c, r1r, new_r1d, r2c, r2r, new_r2d))

        new_r1d = (r1d[1], -r1d[0])
        new_r2d = (r2d[1], -r2d[0])
        if (r1c, r1r, new_r1d, r2c, r2r, new_r2d) not in visited:
            queue.appendleft((r1c, r1r, new_r1d, r2c, r2r, new_r2d, steps, bumps))
            visited.add((r1c, r1r, new_r1d, r2c, r2r, new_r2d))

    print(min_steps, min_bumps)

